'use strict';
// ─────────────────────────────────────────────────────────────────────────────
// Backend/routes/assetCardRoute.js — with Mindteck building photo
// Add to server.js: app.use('/card', require('./routes/assetCardRoute'));
// ─────────────────────────────────────────────────────────────────────────────

const express = require('express');
const router  = express.Router();
const { query } = require('../config/db');

// Mindteck office building photo (embedded — no file needed)
const BUILDING_PHOTO = "data:image/jpeg;base64,";

router.get('/:allocationId', async (req, res) => {
  try {
    const { allocationId } = req.params;
    const result = await query(
      `SELECT
         al.allocation_id, al.asset_id, al.emp_id, al.emp_name, al.emp_email,
         al.department, al.client, al.project, al.accessories, al.allocation_date,
         al.status, al.mobile_no, al.photo_url, al.delivery_method,
         ast.brand, ast.model, ast.config, ast.serial,
         ast.processor, ast.ram, ast.storage,
         ast.warranty_start, ast.warranty_end, ast.vendor, ast.location
       FROM allocations al
       LEFT JOIN assets ast ON ast.asset_id = al.asset_id
       WHERE al.allocation_id = $1`,
      [allocationId]
    );
    if (!result.rows.length) return res.status(404).send(notFoundPage());
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.send(buildCardPage(result.rows[0]));
  } catch (err) {
    console.error('Card page error:', err);
    res.status(500).send(errorPage());
  }
});

function buildCardPage(d) {
  const accessories = Array.isArray(d.accessories) && d.accessories.length
    ? d.accessories : [];
  const statusColor = d.status === 'Active' ? '#16a34a' : '#64748b';
  const statusBg    = d.status === 'Active' ? '#dcfce7' : '#f1f5f9';
  const allocDate   = d.allocation_date
    ? new Date(d.allocation_date).toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' })
    : '—';
  const warrantyEnd = d.warranty_end
    ? new Date(d.warranty_end).toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' })
    : '—';
  const warrantyOk = d.warranty_end && new Date(d.warranty_end) > new Date();
  const photoHtml  = d.photo_url && d.photo_url.startsWith('data:image')
    ? `<img src="${d.photo_url}" alt="${d.emp_name}" class="emp-photo"/>`
    : `<div class="emp-photo-placeholder">${getInitials(d.emp_name)}</div>`;

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1.0"/>
  <title>Asset Card — ${d.asset_id} | ${d.emp_name}</title>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;
         background:#0f172a;min-height:100vh;padding:0;
         display:flex;flex-direction:column;align-items:center}

    /* Building hero banner */
    .building-banner{width:100%;max-width:480px;position:relative;height:160px;overflow:hidden}
    .building-banner img{width:100%;height:100%;object-fit:cover;object-position:center 40%;
                          filter:brightness(.75)}
    .building-overlay{position:absolute;inset:0;
                       background:linear-gradient(to bottom,rgba(15,23,42,.3),rgba(15,23,42,.85));
                       display:flex;flex-direction:column;align-items:flex-start;
                       justify-content:flex-end;padding:14px 20px}
    .company-name{color:#fff;font-size:18px;font-weight:900;letter-spacing:.08em}
    .company-tag{color:rgba(255,255,255,.7);font-size:11px;margin-top:2px}
    .asset-badge{position:absolute;top:14px;right:16px;
                 background:rgba(0,0,0,.5);border:1px solid rgba(255,255,255,.3);
                 border-radius:10px;padding:6px 14px;text-align:right;backdrop-filter:blur(8px)}
    .asset-badge-label{color:rgba(255,255,255,.6);font-size:9px;
                        text-transform:uppercase;letter-spacing:.1em;display:block}
    .asset-badge-id{color:#fff;font-size:20px;font-weight:800;
                    font-family:monospace;display:block;margin-top:1px}

    /* Card */
    .card{background:#fff;width:100%;max-width:480px;
          box-shadow:0 30px 80px rgba(0,0,0,.6);flex:1}

    /* Employee header */
    .emp-header{background:linear-gradient(135deg,#1d3461 0%,#1d5c3c 100%);
                padding:20px 22px;display:flex;align-items:center;gap:16px}
    .emp-photo{width:70px;height:70px;border-radius:50%;object-fit:cover;
               border:3px solid rgba(255,255,255,.5);flex-shrink:0}
    .emp-photo-placeholder{width:70px;height:70px;border-radius:50%;flex-shrink:0;
                            background:rgba(255,255,255,.2);border:3px solid rgba(255,255,255,.4);
                            display:flex;align-items:center;justify-content:center;
                            color:#fff;font-size:22px;font-weight:700}
    .emp-name{color:#fff;font-size:19px;font-weight:700}
    .emp-id{color:rgba(255,255,255,.7);font-size:12px;margin-top:2px}
    .emp-dept{color:rgba(255,255,255,.6);font-size:11px;margin-top:2px}
    .status-pill{display:inline-block;background:${statusBg};color:${statusColor};
                 font-size:10px;font-weight:700;padding:3px 10px;border-radius:20px;
                 margin-top:6px;text-transform:uppercase;letter-spacing:.05em}

    /* Sections */
    .section{padding:16px 20px;border-bottom:1px solid #f1f5f9}
    .section:last-child{border-bottom:none}
    .sec-label{font-size:9px;font-weight:800;text-transform:uppercase;
               letter-spacing:.12em;color:#1d5c3c;margin-bottom:12px;
               display:flex;align-items:center;gap:8px}
    .sec-label::after{content:'';flex:1;height:1px;background:#e2e8f0}

    /* Info grid */
    .info-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}
    .info-item{background:#f8fafc;border-radius:10px;padding:10px 12px;
               border:1px solid #f1f5f9}
    .info-item.full{grid-column:1/-1}
    .info-key{font-size:10px;color:#94a3b8;font-weight:600;
              text-transform:uppercase;letter-spacing:.05em;margin-bottom:3px}
    .info-val{font-size:13px;color:#1e293b;font-weight:700;line-height:1.3}
    .info-val.mono{font-family:monospace;font-size:12px;color:#1d5c3c}
    .info-val.warranty-ok{color:#16a34a}
    .info-val.warranty-exp{color:#dc2626}

    /* Accessories */
    .acc-grid{display:flex;flex-wrap:wrap;gap:6px}
    .acc-chip{background:#f0fdf4;color:#14532d;border:1px solid #bbf7d0;
              border-radius:20px;font-size:11px;font-weight:600;padding:4px 10px}

    /* Footer */
    .card-footer{background:#f8fafc;padding:16px 20px;
                 border-top:2px solid #1d5c3c;text-align:center}
    .footer-logo{font-size:14px;font-weight:900;color:#1d3461;letter-spacing:.06em}
    .footer-text{font-size:11px;color:#94a3b8;margin-top:4px;line-height:1.6}
    .scan-info{font-size:9px;color:#cbd5e1;margin-top:6px;font-family:monospace}

    @media(max-width:480px){
      .building-banner{height:130px}
      .info-grid{grid-template-columns:1fr}
      .info-item.full{grid-column:1}
    }
  </style>
</head>
<body>

<!-- Mindteck Building Banner -->
<div class="building-banner">
  <img src="${BUILDING_PHOTO}" alt="Mindteck Office"/>
  <div class="building-overlay">
    <div class="company-name">MINDTECK</div>
    <div class="company-tag">IT Asset Management System</div>
  </div>
  <div class="asset-badge">
    <span class="asset-badge-label">Asset No</span>
    <span class="asset-badge-id">${d.asset_id}</span>
  </div>
</div>

<div class="card">

  <!-- Employee -->
  <div class="emp-header">
    ${photoHtml}
    <div>
      <div class="emp-name">${d.emp_name}</div>
      <div class="emp-id">${d.emp_id || ''}</div>
      <div class="emp-dept">${d.department || ''}</div>
      <span class="status-pill">${d.status || 'Active'}</span>
    </div>
  </div>

  <!-- Laptop Details -->
  <div class="section">
    <div class="sec-label">💻 Laptop Details</div>
    <div class="info-grid">
      <div class="info-item"><div class="info-key">Brand</div><div class="info-val">${d.brand || '—'}</div></div>
      <div class="info-item"><div class="info-key">Model</div><div class="info-val">${d.model || '—'}</div></div>
      <div class="info-item full"><div class="info-key">Configuration</div><div class="info-val">${d.config || '—'}</div></div>
      <div class="info-item full"><div class="info-key">Serial Number</div><div class="info-val mono">${d.serial || '—'}</div></div>
      ${d.processor ? `<div class="info-item"><div class="info-key">Processor</div><div class="info-val">${d.processor}</div></div>` : ''}
      ${d.ram ? `<div class="info-item"><div class="info-key">RAM</div><div class="info-val">${d.ram}</div></div>` : ''}
      ${d.storage ? `<div class="info-item"><div class="info-key">Storage</div><div class="info-val">${d.storage}</div></div>` : ''}
    </div>
  </div>

  <!-- Allocation Details -->
  <div class="section">
    <div class="sec-label">📋 Allocation Details</div>
    <div class="info-grid">
      <div class="info-item"><div class="info-key">Allocation Date</div><div class="info-val">${allocDate}</div></div>
      <div class="info-item"><div class="info-key">Allocation ID</div><div class="info-val mono" style="font-size:10px">${d.allocation_id}</div></div>
      ${d.project ? `<div class="info-item"><div class="info-key">Project</div><div class="info-val">${d.project}</div></div>` : ''}
      ${d.client  ? `<div class="info-item"><div class="info-key">Client</div><div class="info-val">${d.client}</div></div>` : ''}
      <div class="info-item">
        <div class="info-key">Warranty Until</div>
        <div class="info-val ${warrantyOk ? 'warranty-ok' : 'warranty-exp'}">${warrantyEnd}</div>
      </div>
      ${d.location ? `<div class="info-item"><div class="info-key">Location</div><div class="info-val">${d.location}</div></div>` : ''}
    </div>
  </div>

  <!-- Accessories -->
  ${accessories.length ? `
  <div class="section">
    <div class="sec-label">📦 Accessories Included</div>
    <div class="acc-grid">
      ${accessories.map(a => `<span class="acc-chip">✓ ${a}</span>`).join('')}
    </div>
  </div>` : ''}

  <!-- Contact -->
  <div class="section">
    <div class="sec-label">📞 Contact</div>
    <div class="info-grid">
      <div class="info-item full"><div class="info-key">Work Email</div><div class="info-val" style="font-size:12px">${d.emp_email || '—'}</div></div>
      ${d.mobile_no ? `<div class="info-item full"><div class="info-key">Mobile</div><div class="info-val">${d.mobile_no}</div></div>` : ''}
    </div>
  </div>

  <!-- Footer -->
  <div class="card-footer">
    <div class="footer-logo">MINDTECK</div>
    <div class="footer-text">
      IT Asset Management · sysadmin@mindteck.us<br/>
      For support, contact your IT team
    </div>
    <div class="scan-info">Scanned · ${new Date().toLocaleDateString('en-IN')} · ${d.allocation_id}</div>
  </div>

</div>
</body>
</html>`;
}

function getInitials(name) {
  if (!name) return '?';
  return name.split(' ').map(n => n[0]).join('').slice(0,2).toUpperCase();
}

function notFoundPage() {
  return `<!DOCTYPE html><html><head><meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>Not Found</title>
  <style>body{font-family:Arial,sans-serif;background:#0f172a;display:flex;align-items:center;
  justify-content:center;min-height:100vh;margin:0}
  .box{background:#1e293b;border-radius:16px;padding:40px;text-align:center;max-width:360px;color:#fff}
  p{color:#94a3b8;font-size:14px;margin-top:8px}</style>
  </head><body><div class="box">
  <div style="font-size:48px">🔍</div>
  <h2 style="margin-top:16px">Asset Not Found</h2>
  <p>This QR code does not match any asset. Please contact IT.</p>
  <p style="margin-top:12px;font-size:12px;color:#64748b">sysadmin@mindteck.us</p>
  </div></body></html>`;
}

function errorPage() {
  return `<!DOCTYPE html><html><head><meta charset="UTF-8"/><title>Error</title>
  <style>body{font-family:Arial,sans-serif;background:#0f172a;display:flex;align-items:center;
  justify-content:center;min-height:100vh;margin:0}
  .box{background:#1e293b;border-radius:16px;padding:40px;text-align:center;max-width:360px;color:#fff}</style>
  </head><body><div class="box">
  <div style="font-size:48px">⚠️</div>
  <h2 style="margin-top:16px">Something went wrong</h2>
  <p style="color:#94a3b8;font-size:14px;margin-top:8px">Please try again or contact IT.</p>
  </div></body></html>`;
}

module.exports = router;